{
  "design_type": "simple_multiarm",
  "unit_of_randomization_canonical": "individual participant",
  "is_clustered": false,
  "analysis_unit_canonical": null,
  "primary_outcomes_dedup": [
    "Account opening at Banco Agricola",
    "Savings balances in the bank accounts opened for the study",
    "Savings in other instruments",
    "Remittances"
  ],
  "arms": [
    {
      "arm_id": "arm_comp",
      "name": "Comparison group (talk only; no account offer)",
      "role": "control",
      "description": "Participants received the marketer talk emphasizing benefits of remitting into accounts and ATM/debit access, but received no offer to open an account.",
      "evidence_quote_ids": [
        "eq1",
        "eq2"
      ]
    },
    {
      "arm_id": "arm_t1",
      "name": "Treatment 1: Assistance opening recipient-only account in El Salvador",
      "role": "treatment",
      "description": "Offer of assistance in setting up an account in the name of someone in El Salvador, into which the migrant could remit, granting the recipient full control of the deposits.",
      "evidence_quote_ids": [
        "eq1",
        "eq3"
      ]
    },
    {
      "arm_id": "arm_t2",
      "name": "Treatment 2: Joint account (migrant + recipient) with ATM access/monitoring",
      "role": "treatment",
      "description": "Offer of a joint account where the recipient and the remitter have access through ATM cards; allows monitoring but no enforcement by the migrant.",
      "evidence_quote_ids": [
        "eq1",
        "eq4"
      ]
    },
    {
      "arm_id": "arm_t3",
      "name": "Treatment 3: Treatment 2 + migrant-only account (full control)",
      "role": "treatment",
      "description": "Treatment 2 plus an account only in the name of the migrant, providing full ability to control funds in the account.",
      "evidence_quote_ids": [
        "eq1",
        "eq5"
      ]
    }
  ],
  "factors": [],
  "assignment_rules": [
    "Random assignment of migrants to one of four groups (three treatment groups or a comparison group) with equal (25%) probability.",
    "All participants received a marketer visit with a standardized talk emphasizing benefits of remitting into accounts and recipient ATM/debit access; only treatment arms received an account-opening offer corresponding to their assignment."
  ],
  "design_completeness": "complete",
  "extraction_sources": [
    "registry"
  ],
  "evidence_quotes": [
    {
      "id": "eq1",
      "source_doc": "registry",
      "quote": "Migrants were randomly assigned to one of three treatment groups or a comparison group, each with equal (25%) probability.",
      "supports": "Number of arms and equal-probability individual-level random assignment."
    },
    {
      "id": "eq2",
      "source_doc": "registry",
      "quote": "The control group only received the talk but no offer to open an account.",
      "supports": "Definition of the comparison/control condition."
    },
    {
      "id": "eq3",
      "source_doc": "registry",
      "quote": "Treatment 1: Offer of assistance in setting up an account in the name of someone in El Salvador, into which the migrant could remit, granting the recipient full control of the deposits",
      "supports": "Content of Treatment 1 arm."
    },
    {
      "id": "eq4",
      "source_doc": "registry",
      "quote": "Treatment 2: Offer a joint account where the recipient and the remitter would have access through ATM cards, allowing monitoring, but no enforcement on the part of the migrant",
      "supports": "Content of Treatment 2 arm."
    },
    {
      "id": "eq5",
      "source_doc": "registry",
      "quote": "Treatment 3: Treatment 2 plus an account only in the name of the migrant, providing full ability to control funds in the account.",
      "supports": "Content of Treatment 3 arm."
    },
    {
      "id": "eq6",
      "source_doc": "registry",
      "quote": "All project participants were visited by marketers who emphasized the benefits of remitting funds directly into accounts and of remittance-recipient access to funds via ATM/debit cards (rather than having to wait in a teller line to receive a remittance).",
      "supports": "Common component (talk) delivered to all arms."
    }
  ],
  "notes": "Registry text describes a 4-arm individually randomized design (3 treatments + comparison/control), with a common marketer talk delivered to all participants and differential account-opening offers by treatment status. No explicit analysis unit is stated beyond individual migrant assignment."
}

{
  "design_type": "factorial",
  "unit_of_randomization_canonical": "individual participant",
  "is_clustered": false,
  "analysis_unit_canonical": null,
  "primary_outcomes_dedup": [
    "Guesses about whether a paper has been published and if yes, in which journal",
    "Guesses about the number of citations a paper has",
    "Guesses about the overall quality of the paper"
  ],
  "arms": [
    {
      "arm_id": "arm1",
      "name": "No information",
      "role": "experimental",
      "description": "Subjects do not receive any information about the author of the paper associated with the abstract.",
      "evidence_quote_ids": [
        "eq2"
      ]
    },
    {
      "arm_id": "arm2",
      "name": "Name information",
      "role": "experimental",
      "description": "Subjects see the author's name for each abstract/paper.",
      "evidence_quote_ids": [
        "eq2"
      ]
    },
    {
      "arm_id": "arm3",
      "name": "Institution information",
      "role": "experimental",
      "description": "Subjects see the author's institution for each abstract/paper.",
      "evidence_quote_ids": [
        "eq2"
      ]
    },
    {
      "arm_id": "arm4",
      "name": "Name and institution information",
      "role": "experimental",
      "description": "Subjects see both the author's name and institution for each abstract/paper.",
      "evidence_quote_ids": [
        "eq2"
      ]
    }
  ],
  "factors": [
    {
      "factor_id": "f1",
      "name": "Name information shown",
      "levels": [
        {
          "level_id": "f1l1",
          "name": "No name information",
          "description": "Author name not shown.",
          "evidence_quote_ids": [
            "eq2"
          ]
        },
        {
          "level_id": "f1l2",
          "name": "Name information",
          "description": "Author name shown.",
          "evidence_quote_ids": [
            "eq2"
          ]
        }
      ]
    },
    {
      "factor_id": "f2",
      "name": "Institution information shown",
      "levels": [
        {
          "level_id": "f2l1",
          "name": "No institution information",
          "description": "Author institution not shown.",
          "evidence_quote_ids": [
            "eq2"
          ]
        },
        {
          "level_id": "f2l2",
          "name": "Institution information",
          "description": "Author institution shown.",
          "evidence_quote_ids": [
            "eq2"
          ]
        }
      ]
    }
  ],
  "assignment_rules": [
    "Subjects are randomly assigned into one of four conditions: no information; name information; institution information; name and institution information."
  ],
  "design_completeness": "complete",
  "extraction_sources": [
    "registry"
  ],
  "evidence_quotes": [
    {
      "id": "eq1",
      "source_doc": "registry",
      "quote": "Subjects will be randomly assigned into one of the four treatments. Depending on the treatment, subjects will receive no information, partial information or full information about these abstracts.",
      "supports": "Random assignment to four treatments/conditions with differing information levels."
    },
    {
      "id": "eq2",
      "source_doc": "registry",
      "quote": "Subjects will be randomly assigned into one of the four conditions: no information, name information, institution information, name and institution information. In the no information treatment, subjects will not receive any information about the author of the paper. In the name information, subjects will know the name of the author. In the institution information, subjects will know the institution of the author. In the name and institution information, subjects will know both the name and the institution of the author.",
      "supports": "Explicit four experimental conditions/arms and their content; implies a 2x2 factorial over name info and institution info."
    },
    {
      "id": "eq3",
      "source_doc": "registry",
      "quote": "PRIMARY_OUTCOMES_RAW: 1. Guesses about whether a paper has been published and if yes, in which journal, 2. Guesses about the number of citations a paper has, 3. Guesses about the overall quality of the paper",
      "supports": "Primary outcomes."
    }
  ],
  "notes": "The registry text also notes that abstracts vary by (true) author gender and institution, but treatment assignment is to information disclosure conditions about author identity (name) and affiliation (institution). Unit of randomization is inferred as individual participants because assignment is described at the subject level and no clustering is mentioned."
}

{
  "design_type": "simple_multiarm",
  "unit_of_randomization_canonical": null,
  "is_clustered": false,
  "analysis_unit_canonical": null,
  "primary_outcomes_dedup": [
    "Group minimum test score"
  ],
  "arms": [
    {
      "arm_id": "A1",
      "name": "Control (no financial incentives)",
      "role": "control",
      "description": "Students are not given any financial incentives.",
      "evidence_quote_ids": [
        "eq2"
      ]
    },
    {
      "arm_id": "A2",
      "name": "Treatment: incentive based on group's lowest performer",
      "role": "treatment",
      "description": "Students are given a financial incentive based on the group's lowest performer.",
      "evidence_quote_ids": [
        "eq1",
        "eq2"
      ]
    },
    {
      "arm_id": "A3",
      "name": "Treatment: incentive based on group's highest performer",
      "role": "treatment",
      "description": "Students are given a financial incentive based on the group's highest performer.",
      "evidence_quote_ids": [
        "eq1",
        "eq2"
      ]
    }
  ],
  "factors": [],
  "assignment_rules": [
    "Students are first placed into groups of three or four students.",
    "Control students receive no financial incentives.",
    "There are two treatment conditions: incentives based on the group's lowest performer vs the group's highest performer."
  ],
  "design_completeness": "partial",
  "extraction_sources": [
    "registry"
  ],
  "evidence_quotes": [
    {
      "id": "eq1",
      "source_doc": "registry",
      "quote": "Students are first placed into groups of three or four students. Then, treatment students are given a financial incentive based on the group's lowest and highest performers respectively.",
      "supports": "Group formation prior to treatment; existence of two treatment conditions defined by whether incentives are based on lowest vs highest performer."
    },
    {
      "id": "eq2",
      "source_doc": "registry",
      "quote": "Students are first placed into groups of three or four students. Control students are not given any financial incentives. There are two treatment conditions; treatment students are given a financial incentive based on the group's lowest and highest performers respectively.",
      "supports": "Presence of a control arm with no incentives; two treatment conditions tied to lowest vs highest performer."
    },
    {
      "id": "eq3",
      "source_doc": "registry",
      "quote": "PRIMARY_OUTCOMES_RAW: Group Minimum Test Score",
      "supports": "Primary outcome definition."
    }
  ],
  "notes": "The registry text does not explicitly state the unit of randomization (individual vs group) or the random assignment procedure; students are placed into groups before treatment, but it is unclear whether treatment is assigned at the student level or group level. Because the unit of randomization is not explicit, it is left null and design completeness is marked partial."
}
